  </div>
  <div class="banner">
    <h2>Mandatory Action: Q3 Access Verification</h2>
  </div>
  <div class="email-content">
    <!-- Familiarity Bias: Personalized greeting -->
    <p>Hi [Employee First Name],</p> 

